import React from 'react';
import './AfkPlanner.css';

class HeroDisplay extends React.Component {
    // constructor(props) {
    //     super(props);
    //     this.state = {
    //       borderColor: 'black'
    //     };
    // }

    // render () {
    //     return (
    //         <div className="hero-display">
    //             <img />
    //         </div>
    //     );
    // }

    getStarImage(stars) {
        let path='';

        switch(stars) {
            case 0:
                path = 'Star0.png'
                break;
            case 1:
                path = 'Star1.png'
                break;
            case 2:
                path = 'Star2.png'
                break;
            case 3:
                path = 'Star3.png'
                break;
            case 4:
                path = 'Star4.png'
                break;
            case 5:
                path = 'Star5.png'
                break;
        }

        return path;
    }

    getStarState (stars){

        if (stars != 0) {
            return <img alt="" className="hero-icon-star" src={this.getStarImage(this.props.stars) || ''}/>
        } else {
            return null
        }

    }

    render() {
        return (
            <div className="hero-display">

                <img alt="" className="hero-icon-image" src={this.props.heroIcon || 'heroicon.png'}/>
                <div className="hero-border" style={{borderColor: this.props.borderColor}} />
                {this.getStarState(this.props.stars || 0)}
                <div className="hero-name">{this.props.heroName}</div>
                
            </div>
        );
      }
    
}

function AfkPlanner() {
    return (
        <div className="afk-container"> 
            <HeroDisplay borderColor='blue' heroName='hogan' heroIcon='heroIcon.png' />
            <HeroDisplay borderColor='red' heroName='nara' />
            <HeroDisplay borderColor='gold' heroName='saveas' />
            <HeroDisplay borderColor='white' heroName='Solise' stars={1} />
            <HeroDisplay borderColor='white' heroName='Solise' stars={2} />
            <HeroDisplay borderColor='white' heroName='Solise' stars={3} />
            <HeroDisplay borderColor='white' heroName='Solise' stars={4} />
            <HeroDisplay borderColor='white' heroName='Solise' stars={5} />
            <HeroDisplay borderColor='white' heroName='Solise' stars={5} />
            <HeroDisplay />
            <HeroDisplay heroName='Add Hero' heroIcon='addHero.png'/>
        </div>
    );
}

export default AfkPlanner;